interface UserProfile {
  name: string;
  bio?: string;
  xp?: number;
  isPremium?: boolean;
}

function displayProfile(user: UserProfile) {
  const bio       = user.bio ?? "No bio yet";
  const xp        = user.xp ?? 0;           // ?? keeps 0 as a valid value
  const isPremium = user.isPremium ?? false;

  console.log(`${user.name}: ${bio}`);
  console.log(`XP: ${xp}, Premium: ${isPremium}`);
}

