interface Address {
  street: string;
  city: string;
  country: string;
}

interface User {
  id: number;
  name: string;
  address?: Address;       // user may not have an address
  employer?: {
    name: string;
    department?: string;   // department may be missing
  };
}

function getUserLocation(user: User): string {
  return user.address?.city ?? "Unknown city";
}

function getDepartment(user: User): string {
  return user.employer?.department ?? "No department";
}

const alice: User = {
  id: 1, name: "Alice",
  address: { street: "123 Main St", city: "San Francisco", country: "USA" },
  employer: { name: "TechCorp" },
};

const bob: User = { id: 2, name: "Bob" };

console.log(`${alice.name}: ${getUserLocation(alice)}, ${getDepartment(alice)}`);
console.log(`${bob.name}: ${getUserLocation(bob)}, ${getDepartment(bob)}`);

// const gives a literal type — TypeScript knows EXACTLY which value
const direction = "north";  // type: "north" (not just string)
const code = 404;           // type: 404 (not just number)

// let gives a wider type — value might change
let status = "pending";     // type: string (could become anything)
let retries = 0;            // type: number

// Practical: const literal types work as discriminants
type Direction = "north" | "south" | "east" | "west";

function describeDirection(d: Direction): string {
  if (d === "north" || d === "south") return `${d} (vertical)`;
  return `${d} (horizontal)`;
}

console.log(describeDirection(direction));  // works because type is "north"
console.log(`Status: ${status}`);
console.log(`Retries: ${retries}`);
